	@Test
	void reorderSegmentPrefersPairAnchoredByOuterBindings() throws Exception {
		StatementPattern encounter = statementPattern("patient", "enc", ex("hasEncounter"));
		StatementPattern observation = statementPattern("enc", "obs", ex("hasObservation"));
		StatementPattern unrelatedA = statementPattern("other", "mid", ex("otherA"));
		StatementPattern unrelatedB = statementPattern("mid", "leaf", ex("otherB"));

		QueryJoinOptimizer optimizer = new QueryJoinOptimizer(
				new PairwiseCostStatistics(Map.of(
						pairKey(ex("hasEncounter"), ex("hasObservation")), 5.0d,
						pairKey(ex("otherA"), ex("otherB")), 1.0d)),
				new EmptyTripleSource());

		List<TupleExpr> reordered = invokeReorderSegment(optimizer,
				List.of(encounter, observation, unrelatedA, unrelatedB),
				Set.of("patient"));

		assertThat(predicates(reordered))
				.as("A pair anchored by outer-bound ?patient should be chosen before a cheaper unrelated pair")
				.containsExactly(ex("hasEncounter"), ex("hasObservation"), ex("otherA"), ex("otherB"));
	}

